// Debugging a mysterious issue by adding excessive logging
function mysteryFunction(input) {
  console.log(`Input received: ${input}`);
  const result = input * 2;
  console.log(`Result after doubling: ${result}`);
  if (result > 10) {
    console.log('Result is greater than 10!');
  }
  console.log(`Final output: ${result}`);
  return result;
}

console.log("WHAT IS GOING ON");
mysteryFunction(5);

This snippet shows the common debugging practice of adding multiple `console.log` statements to trace execution flow and variable states.
